let bb, ps;
let animating = false;
let startF = 0;
let dur = 512;
let effectDone = false;
let holdF = 0;

class Particle {
  constructor(x, y, pal) {
    this.pos = p.createVector(x, y);
    const ang = p.random(p.TWO_PI);
    const spd = p.random(0.5, 2.5);
    this.vel = p.createVector(p.cos(ang) * spd, p.sin(ang) * spd);
    this.r = p.random(1, 3);
    const c = pal.px[p.floor(p.random(pal.px.length))];
    this.col = p.color(c[0], c[1], c[2]);
    this.life = p.random(128, 320);
  }
  update() { this.pos.add(this.vel); this.life -= 0.2; }
  draw() {
    p.noStroke();
    p.fill(p.red(this.col), p.green(this.col), p.blue(this.col), this.life);
    p.ellipse(this.pos.x, this.pos.y, this.r * 2);
  }
  dead() { return this.life <= 0; }
}

class BangSystem {
  constructor(origin, pal) {
    this.particles = [];
    this.origin = origin;
    this.pal = pal;
    this.max = 12;
  }
  update() {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      this.particles[i].update();
      if (this.particles[i].dead()) this.particles.splice(i, 1);
    }
    this.max -= p.random(0.0075, 0.035);
  }
  draw() { for (const pt of this.particles) pt.draw(); }
  emit() {
    for (let i = 0; i < this.max; i++)
      this.particles.push(new Particle(this.origin.pos.x, this.origin.pos.y, this.pal));
  }
}

class BigBang {
  constructor(pal) {
    this.pos = p.createVector(p.width / 2, p.height / 2);
    this.radius = 0;
    this.col = p.color(pal.bg[0], pal.bg[1], pal.bg[2]);
  }
  update() { this.radius += 1; }
  draw() {
    p.noStroke();
    p.fill(this.col);
    p.ellipse(this.pos.x, this.pos.y, this.radius * 2);
  }
}

function init() {
  const palName = p.getSynthVar('color_palette') || 'Northern Lights';
  const pal = BB_PALETTES[palName] || BB_PALETTES['Northern Lights'];
  const spd = p.getSynthVar('animation_speed') || 'normal';
  dur = spd === 'slow' ? 768 : spd === 'fast' ? 320 : 512;
  bb = new BigBang(pal);
  ps = new BangSystem(bb, pal);
  animating = true;
  effectDone = false;
  holdF = 0;
  startF = p.frameCount;
}

function applyFX() {
  const orig = p.get();
  const pg = p.createGraphics(p.width, p.height);

  // Base + warm color shift
  pg.image(orig, 0, 0);
  pg.tint(255, 240, 220);
  pg.image(orig, 0, 0);
  pg.noTint();

  // Film grain
  const grain = p.createGraphics(p.width, p.height);
  grain.loadPixels();
  for (let i = 0; i < grain.pixels.length; i += 4) {
    const v = p.random(30);
    grain.pixels[i] = grain.pixels[i + 1] = grain.pixels[i + 2] = v;
    grain.pixels[i + 3] = 128;
  }
  grain.updatePixels();
  pg.blendMode(p.ADD);
  pg.image(grain, 0, 0);
  pg.blendMode(p.BLEND);

  // Vignette
  pg.push();
  pg.noFill();
  pg.strokeWeight(p.width * 0.4);
  for (let i = 0; i < 50; i++) {
    pg.stroke(0, p.map(i, 0, 50, 0, 100));
    pg.ellipse(p.width / 2, p.height / 2, p.map(i, 0, 50, p.width * 1.5, p.width * 0.8));
  }
  pg.pop();

  // Chromatic aberration
  const rCh = pg.get();
  const gbCh = pg.get();
  pg.tint(255, 0, 0);   pg.image(rCh, 2, 0);
  pg.tint(0, 255, 255); pg.image(gbCh, -2, 0);
  pg.noTint();

  // Bloom
  pg.filter(p.BLUR, 4);
  pg.blend(orig, 0, 0, p.width, p.height, 0, 0, p.width, p.height, p.LIGHTEST);

  p.image(pg, 0, 0);
}

p.setup = () => {
  p.createCanvas(400, 400);
  init();
};

p.draw = () => {
  if (animating) {
    p.background(0);
    if (p.frameCount - startF < dur) {
      bb.update();
      ps.update();
      ps.emit();
    } else {
      animating = false;
      effectDone = false;
    }
    bb.draw();
    ps.draw();
  } else if (!effectDone) {
    applyFX();
    effectDone = true;
  } else {
    holdF++;
    if (holdF > 180) init();
  }
};
